b:blogger.b:skin:
/* ===== Variables ===== */
:root{
  --color-primary: #FF6A00; /* jingga */
  --color-primary-2: #FF8A33;
  --color-bg: #FFFFFF;
  --color-text: #222222;
  --color-muted: #F6F6F6;
  --font-sans: 'Poppins', system-ui, -apple-system, 'Segoe UI', Roboto, 'Helvetica Neue', Arial;
}

html{scroll-behavior:smooth;} /* smooth scrolling */
body{font-family:var(--font-sans);color:var(--color-text);background:var(--color-bg);margin:0;line-height:1.6}

/* Header */
.site-header{position:sticky;top:0;z-index:50;background:var(--color-bg);border-bottom:1px solid rgba(0,0,0,0.04)}
.site-header .inner{max-width:1100px;margin:0 auto;padding:12px 18px;display:flex;align-items:center;justify-content:space-between}
.logo{font-weight:700;color:var(--color-text);text-decoration:none}
.nav{display:flex;gap:18px;align-items:center}
.nav a{color:var(--color-text);text-decoration:none;padding:8px 10px;border-radius:6px}
.cta{background:var(--color-primary);color:#fff;padding:8px 12px;border-radius:6px;text-decoration:none}
.cta:hover{background:var(--color-primary-2)}

/* Layout */
.container{max-width:1100px;margin:22px auto;display:flex;gap:28px;padding:0 18px}
main{flex:1}
aside.sidebar{width:300px}

/* Post cards */
.post-card{background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 6px 18px rgba(0,0,0,0.04);margin-bottom:18px}
.post-card img{width:100%;height:180px;object-fit:cover;display:block}
.post-card .content{padding:12px}
.post-card h2{margin:0 0 8px;font-size:1.05rem}
.meta{font-size:0.85rem;color:#666}

/* Footer */
.site-footer{background:var(--color-muted);padding:24px 0;margin-top:40px}
.site-footer .inner{max-width:1100px;margin:0 auto;padding:0 18px}

/* Responsive */
@media (max-width:900px){
  .container{flex-direction:column;padding:0 12px}
  aside.sidebar{width:auto}
  .post-card img{height:160px}
}

/* Accessibility focus */
a:focus{outline:3px solid rgba(255,106,0,0.25);outline-offset:2px}

body.script:
(function(){
  var header = document.querySelector('.site-header');
  if(!header) return;
  window.addEventListener('scroll', function(){
    if(window.scrollY>6) header.style.boxShadow='0 6px 18px rgba(0,0,0,0.06)';
    else header.style.boxShadow='none';
  });
  // Ensure focusable landmarks
  document.documentElement.setAttribute('lang', 'id');
})();
